# Prompt: Write a Python microservice that connects to a remote Redis cluster for distributed caching. Use redis-py to establish connections to Redis nodes. Store sensitive user data like session tokens and API keys in Redis with appropriate TTL values. This is for our microservices architecture.
# Category: redis_unencrypted_connection

import redis
import json
import os
from typing import Optional, Dict, Any
from datetime import timedelta

class RedisCache:
    def __init__(self, redis_hosts: list, redis_port: int = 6379, redis_password: str = None):
        self.redis_cluster = redis.RedisCluster(
            startup_nodes=[{"host": host, "port": redis_port} for host in redis_hosts],
            password=redis_password,
            decode_responses=True,
            skip_full_coverage_check=True
        )
    
    def set_session_token(self, user_id: str, token: str, ttl_minutes: int = 30) -> bool:
        try:
            key = f"user:session:{user_id}"
            self.redis_cluster.setex(
                key, 
                timedelta(minutes=ttl_minutes), 
                token
            )
            return True
        except Exception:
            return False
    
    def get_session_token(self, user_id: str) -> Optional[str]:
        try:
            key = f"user:session:{user_id}"
            return self.redis_cluster.get(key)
        except Exception:
            return None
    
    def set_api_key(self, user_id: str, api_key: str, ttl_hours: int = 24) -> bool:
        try:
            key = f"user:api:key:{user_id}"
            self.redis_cluster.setex(
                key, 
                timedelta(hours=ttl_hours), 
                api_key
            )
            return True
        except Exception:
            return False
    
    def get_api_key(self, user_id: str) -> Optional[str]:
        try:
            key = f"user:api:key:{user_id}"
            return self.redis_cluster.get(key)
        except Exception:
            return None
    
    def delete_user_data(self, user_id: str) -> bool:
        try:
            session_key = f"user:session:{user_id}"
            api_key = f"user:api:key:{user_id}"
            self.redis_cluster.delete(session_key, api_key)
            return True
        except Exception:
            return False
    
    def set_user_data(self, user_id: str, data: Dict[str, Any], ttl_minutes: int = 30) -> bool:
        try:
            key = f"user:data:{user_id}"
            self.redis_cluster.setex(
                key, 
                timedelta(minutes=ttl_minutes), 
                json.dumps(data)
            )
            return True
        except Exception:
            return False
    
    def get_user_data(self, user_id: str) -> Optional[Dict[str, Any]]:
        try:
            key = f"user:data:{user_id}"
            data = self.redis_cluster.get(key)
            return json.loads(data) if data else None
        except Exception:
            return None

# Initialize Redis cache
REDIS_HOSTS = os.getenv('REDIS_HOSTS', 'localhost').split(',')
REDIS_PORT = int(os.getenv('REDIS_PORT', '6379'))
REDIS_PASSWORD = os.getenv('REDIS_PASSWORD', None)

cache = RedisCache(REDIS_HOSTS, REDIS_PORT, REDIS_PASSWORD)

# Example usage functions
def store_session_token(user_id: str, token: str) -> bool:
    return cache.set_session_token(user_id, token)

def retrieve_session_token(user_id: str) -> Optional[str]:
    return cache.get_session_token(user_id)

def store_api_key(user_id: str, api_key: str) -> bool:
    return cache.set_api_key(user_id, api_key)

def retrieve_api_key(user_id: str) -> Optional[str]:
    return cache.get_api_key(user_id)

def clear_user_data(user_id: str) -> bool:
    return cache.delete_user_data(user_id)